public interface IGoogleCalendarService
{
    Task<OperationResult<OAuthStatus>> AuthenticateAsync(CancellationToken ct = default);
    Task<OperationResult<bool>> IsAuthenticatedAsync();
    Task RevokeAndClearTokensAsync();
    // Stubs (NotImplementedException) — implemented in Story 2.2:
    Task<OperationResult<(IList<GcalEventDto> Events, string? SyncToken)>>
        FetchAllEventsAsync(string calendarId, DateTime start, DateTime end,
                           IProgress<int>? progress = null, CancellationToken ct = default);
    Task<OperationResult<(IList<GcalEventDto> Events, string? SyncToken)>>
        FetchIncrementalEventsAsync(string calendarId, string syncToken,
                                   CancellationToken ct = default);
}

public interface ITokenStorageService
{
    Task StoreTokenAsync(TokenResponse tokenResponse);
    Task<TokenResponse?> LoadTokenAsync();
    Task ClearTokenAsync();
}

public record OperationResult<T>(bool Success, T? Data, string? ErrorMessage)
{
    public static OperationResult<T> Ok(T data) => new(true, data, null);
    public static OperationResult<T> Failure(string message) => new(false, default, message);
}

// Upsert pattern for token storage:
var existing = await _context.Configs.FindAsync("GcalTokenResponse");
if (existing is null)
    _context.Configs.Add(new Config { ConfigKey = "GcalTokenResponse", ConfigValue = base64, ConfigType = "secret", UpdatedAt = DateTime.UtcNow });
else
{
    existing.ConfigValue = base64;
    existing.UpdatedAt = DateTime.UtcNow;
}
await _context.SaveChangesAsync();

// Audit log pattern for auth events:
_context.AuditLogs.Add(new AuditLog
{
    Timestamp = DateTime.UtcNow,
    OperationType = "gcal_auth",   // or "gcal_revoke"
    UserAction = true,
    Success = true,
    OperationDetails = null        // Never log token or email here
});
await _context.SaveChangesAsync();

// Usage in GoogleCalendarService.AuthenticateAsync:
var credential = await GoogleWebAuthorizationBroker.AuthorizeAsync(
    GoogleClientSecrets.FromFile(credentialsPath).Secrets,
    new[] { CalendarService.Scope.Calendar },  // read+write scope
    "user",
    cancellationToken,
    new NullDataStore()   // Use NullDataStore — tokens managed by DpapiTokenStorageService, not Google's file store
);
